133→mod tests {
134→    use super::*;
135→    use std::fs;
136→    use tempfile::tempdir;
137→
138→    /// Helper: create a valid benchmark case directory with all required files.
139→    fn create_case_dir(parent: &Path, name: &str, code: &str, context: &str, expected: &Expected) {
140→        let dir = parent.join(name);
141→        fs::create_dir_all(&dir).unwrap();
142→        fs::write(dir.join("code.rs"), code).unwrap();
143→        fs::write(dir.join("context.md"), context).unwrap();
144→        fs::write(
145→            dir.join("expected.json"),
146→            serde_json::to_string_pretty(expected).unwrap(),
147→        )
148→        .unwrap();
149→    }
