151→    fn sample_expected() -> Expected {
152→        Expected {
153→            must_find: vec![ExpectedFinding {
154→                id: "race-condition-1".to_string(),
155→                severity: "critical".to_string(),
156→                description: "TOCTOU race in create_issue".to_string(),
157→                location: "issues.rs:48-62".to_string(),
158→            }],
159→            must_not_flag: vec![MustNotFlag {
160→                id: "fp-1".to_string(),
