                location: "issues.rs:48-62".to_string(),
            }],
            must_not_flag: vec![MustNotFlag {
                id: "fp-1".to_string(),
                description: "Using conn.last_insert_rowid() inside a transaction is correct"
                    .to_string(),
                location: Some("issues.rs:70".to_string()),
            }],
        }
    }

