 277→**code.rs:**
 278→```rust
 279→use serde::{Deserialize, Serialize};
 280→use std::fmt;
 281→
 282→/// Verdict from the arbiter after evaluating review failures.
 283→#[derive(Debug, Clone, Default, Serialize, Deserialize, PartialEq)]
 284→#[serde(rename_all = "SCREAMING_SNAKE_CASE")]
 285→pub enum ArbiterVerdict {
 286→    /// Proceed despite review failure (findings are acceptable).
 287→    Proceed,
 288→    /// Spawn fix agent and retry review.
 289→    Fix,
 290→    /// Require human decision (policy, architecture, out of budget).
 291→    /// DEAD CODE: No mechanism exists for human input in the pipeline.
 292→    /// The pipeline is fully autonomous — there is no pause-and-wait
 293→    /// or notification system that could deliver this to a human.
 294→    #[default]
 295→    Escalate,
 296→}
 297→
 298→impl ArbiterVerdict {
 299→    pub fn is_actionable(&self) -> bool {
 300→        matches!(self, Self::Proceed | Self::Fix)
 301→    }
 302→
 303→    /// Check if this verdict requires human intervention.
 304→    /// DEAD CODE: Returns true for Escalate, but no caller ever
 305→    /// uses this result to actually pause the pipeline or notify a human.
 306→    pub fn requires_human(&self) -> bool {
 307→        matches!(self, Self::Escalate)
 308→    }
 309→}
 310→
 311→impl fmt::Display for ArbiterVerdict {
 312→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 313→        match self {
 314→            Self::Proceed => write!(f, "PROCEED"),
 315→            Self::Fix => write!(f, "FIX"),
 316→            Self::Escalate => write!(f, "ESCALATE"),
 317→        }
 318→    }
 319→}
 320→
 321→/// Decision from the arbiter with full context.
 322→#[derive(Debug, Clone, Serialize, Deserialize)]
 323→pub struct ArbiterDecision {
 324→    pub decision: ArbiterVerdict,
 325→    pub reasoning: String,
 326→    pub confidence: f64,
 327→    pub fix_instructions: Option<String>,
 328→    /// Summary for escalation — only set when verdict is Escalate.
 329→    /// DEAD: Since Escalate is never actionable, this is never used.
 330→    pub escalation_summary: Option<String>,
 331→    pub suggested_fix_budget: Option<u32>,
 332→    pub addressed_findings: Vec<String>,
 333→}
 334→
 335→impl ArbiterDecision {
 336→    pub fn proceed(reasoning: &str, confidence: f64) -> Self {
 337→        Self {
 338→            decision: ArbiterVerdict::Proceed,
 339→            reasoning: reasoning.to_string(),
 340→            confidence,
 341→            fix_instructions: None,
 342→            escalation_summary: None,
 343→            suggested_fix_budget: None,
 344→            addressed_findings: Vec::new(),
 345→        }
 346→    }
 347→
 348→    pub fn fix(reasoning: &str, confidence: f64, instructions: &str) -> Self {
 349→        Self {
 350→            decision: ArbiterVerdict::Fix,
 351→            reasoning: reasoning.to_string(),
 352→            confidence,
 353→            fix_instructions: Some(instructions.to_string()),
 354→            escalation_summary: None,
 355→            suggested_fix_budget: None,
 356→            addressed_findings: Vec::new(),
 357→        }
 358→    }
 359→
 360→    /// Create an ESCALATE decision.
 361→    /// DEAD: No code path creates an Escalate decision that results in
 362→    /// actual human interaction. The pipeline treats unknown verdicts as failures.
 363→    pub fn escalate(reasoning: &str, confidence: f64, summary: &str) -> Self {
 364→        Self {
 365→            decision: ArbiterVerdict::Escalate,
 366→            reasoning: reasoning.to_string(),
 367→            confidence,
 368→            fix_instructions: None,
 369→            escalation_summary: Some(summary.to_string()),
 370→            suggested_fix_budget: None,
 371→            addressed_findings: Vec::new(),
 372→        }
 373→    }
 374→
 375→    pub fn summary(&self) -> String {
 376→        match &self.decision {
 377→            ArbiterVerdict::Proceed => {
 378→                format!("PROCEED ({:.0}% confidence): {}", self.confidence * 100.0, self.reasoning)
 379→            }
 380→            ArbiterVerdict::Fix => {
 381→                format!("FIX ({:.0}% confidence): {}", self.confidence * 100.0, self.reasoning)
 382→            }
 383→            ArbiterVerdict::Escalate => {
 384→                format!("ESCALATE ({:.0}% confidence): {}", self.confidence * 100.0, self.reasoning)
 385→            }
 386→        }
 387→    }
 388→}
 389→
 390→/// Parse an LLM response into an ArbiterDecision.
 391→pub fn parse_llm_verdict(response: &str, findings: &[String]) -> ArbiterDecision {
 392→    let verdict_str = extract_verdict(response);
 393→    let reasoning = extract_reasoning(response);
 394→    let confidence = extract_confidence(response);
 395→
 396→    match verdict_str.to_uppercase().as_str() {
 397→        "PROCEED" => ArbiterDecision::proceed(&reasoning, confidence),
 398→        "FIX" => {
 399→            let instructions = extract_instructions(response);
 400→            ArbiterDecision::fix(&reasoning, confidence, &instructions)
 401→        }
 402→        // DEAD: LLM might output "ESCALATE" but the pipeline treats it as a failure
 403→        // since there's no human escalation path.
 404→        "ESCALATE" => {
 405→            let summary = extract_summary(response);
 406→            ArbiterDecision::escalate(&reasoning, confidence, &summary)
 407→        }
 408→        _ => {
 409→            // Unknown verdict defaults to Escalate — which is also dead
 410→            ArbiterDecision::escalate(
 411→                &format!("Unrecognized verdict '{}', defaulting to escalate", verdict_str),
 412→                0.0,
 413→                "LLM returned unrecognized verdict",
 414→            )
 415→        }
 416→    }
 417→}
 418→
 419→// Stub extractors
 420→fn extract_verdict(response: &str) -> String { "PROCEED".to_string() }
 421→fn extract_reasoning(response: &str) -> String { String::new() }
 422→fn extract_confidence(response: &str) -> f64 { 0.5 }
 423→fn extract_instructions(response: &str) -> String { String::new() }
 424→fn extract_summary(response: &str) -> String { String::new() }
 425→```
