 501→**code.rs:**
 502→```rust
 503→use serde::{Deserialize, Serialize};
 504→use anyhow;
 505→
 506→/// Permission mode controls what tools are available and how iteration approval works.
 507→///
 508→/// | Mode       | When to use              | Gate behavior                           |
 509→/// |------------|--------------------------|-----------------------------------------|
 510→/// | `Readonly` | Auditing / inspection    | Restricts toolset to read-only tools    |
 511→/// | `Standard` | Normal development       | Threshold-based auto-approve (<=N files)|
 512→/// | `Autonomous`| Well-tested, CI         | Auto-approves all iterations            |
 513→/// | `Strict`   | Sensitive / high-risk    | Requires manual approval every iteration|
 514→///
 515→/// PROBLEM: Strict is documented as requiring manual approval, but the implementation
 516→/// does not differentiate it from Standard. No code path checks for Strict specifically.
 517→#[derive(Debug, Clone, Copy, PartialEq, Eq, Default, Serialize, Deserialize)]
 518→#[serde(rename_all = "lowercase")]
 519→pub enum PermissionMode {
 520→    /// Require approval for every iteration (sensitive phases).
 521→    /// DEAD: No gate logic differentiates this from Standard.
 522→    Strict,
 523→    /// Approve phase start, auto-continue iterations (default).
 524→    #[default]
 525→    Standard,
 526→    /// Auto-approve all iterations.
 527→    Autonomous,
 528→    /// Read-only: restrict to read-only tools.
 529→    Readonly,
 530→}
 531→
 532→impl std::fmt::Display for PermissionMode {
 533→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 534→        match self {
 535→            PermissionMode::Strict => write!(f, "strict"),
 536→            PermissionMode::Standard => write!(f, "standard"),
 537→            PermissionMode::Autonomous => write!(f, "autonomous"),
 538→            PermissionMode::Readonly => write!(f, "readonly"),
 539→        }
 540→    }
 541→}
 542→
 543→impl std::str::FromStr for PermissionMode {
 544→    type Err = anyhow::Error;
 545→
 546→    fn from_str(s: &str) -> Result<Self, Self::Err> {
 547→        match s.to_lowercase().as_str() {
 548→            "strict" => Ok(PermissionMode::Strict),
 549→            "standard" => Ok(PermissionMode::Standard),
 550→            "autonomous" => Ok(PermissionMode::Autonomous),
 551→            "readonly" => Ok(PermissionMode::Readonly),
 552→            _ => anyhow::bail!(
 553→                "Invalid permission mode '{}'. Valid values: strict, standard, autonomous, readonly",
 554→                s
 555→            ),
 556→        }
 557→    }
 558→}
 559→
 560→/// Returns restricted tool set for a permission mode, or None for unrestricted modes.
 561→///
 562→/// NOTE: Strict returns None (unrestricted) — identical to Standard.
 563→/// If Strict truly required manual approval, this function would need to return
 564→/// a different tool set or the gate logic would need a separate check.
 565→pub fn tools_for_permission_mode(mode: PermissionMode) -> Option<Vec<String>> {
 566→    match mode {
 567→        PermissionMode::Readonly => Some(vec![
 568→            "Read".to_string(),
 569→            "Glob".to_string(),
 570→            "Grep".to_string(),
 571→            "Bash".to_string(), // read-only commands only
 572→        ]),
 573→        PermissionMode::Strict => None,     // SAME AS STANDARD — dead variant
 574→        PermissionMode::Standard => None,    // Unrestricted
 575→        PermissionMode::Autonomous => None,  // Unrestricted
 576→    }
 577→}
 578→
 579→/// Gate check: should auto-approve this iteration?
 580→///
 581→/// NOTE: Strict is not checked here at all — it falls through to the
 582→/// Standard behavior. There is no "require manual approval" code path.
 583→pub fn should_auto_approve(mode: PermissionMode, files_changed: usize, threshold: usize) -> bool {
 584→    match mode {
 585→        PermissionMode::Autonomous => true,
 586→        PermissionMode::Readonly => false,
 587→        // Strict falls through to Standard — no special handling
 588→        PermissionMode::Strict | PermissionMode::Standard => {
 589→            files_changed <= threshold
 590→        }
 591→    }
 592→}
 593→
 594→#[cfg(test)]
 595→mod tests {
 596→    use super::*;
 597→
 598→    #[test]
 599→    fn test_permission_mode_display() {
 600→        assert_eq!(PermissionMode::Strict.to_string(), "strict");
 601→        assert_eq!(PermissionMode::Standard.to_string(), "standard");
 602→    }
 603→
 604→    #[test]
 605→    fn test_tools_for_strict_mode() {
 606→        // Strict returns None — same as Standard
 607→        assert!(tools_for_permission_mode(PermissionMode::Strict).is_none());
 608→    }
 609→
 610→    #[test]
 611→    fn test_strict_auto_approve_same_as_standard() {
 612→        // Strict behaves identically to Standard
 613→        assert_eq!(
 614→            should_auto_approve(PermissionMode::Strict, 3, 5),
 615→            should_auto_approve(PermissionMode::Standard, 3, 5),
 616→        );
 617→    }
 618→}
 619→```
