 690→use serde_json::Value;
 691→
 692→#[derive(Debug, Clone)]
 693→pub enum StreamJsonEvent {
 694→    Text { text: String },
 695→    Thinking { text: String },
 696→    ToolStart { tool_name: String, tool_id: String, input_summary: String },
 697→    ToolResult { tool_id: String, output_summary: String },
 698→    Error { message: String },
 699→    Done,
 700→}
 701→
 702→/// Parse a stream JSON line into a structured event.
 703→///
 704→/// VERBOSE: Uses deeply nested if/if-let chains where let-chains would be clearer.
 705→pub fn parse_stream_json_line(line: &str) -> StreamJsonEvent {
 706→    let trimmed = line.trim();
 707→    if trimmed.is_empty() {
 708→        return StreamJsonEvent::Done;
 709→    }
 710→
 711→    let json: Value = match serde_json::from_str(trimmed) {
 712→        Ok(v) => v,
 713→        Err(_) => return StreamJsonEvent::Text { text: trimmed.to_string() },
 714→    };
 715→
 716→    let msg_type = json.get("type").and_then(|t| t.as_str()).unwrap_or("");
 717→
 718→    // VERBOSE: Nested if/if-let — 3 levels of indentation for a simple condition.
 719→    // Could be: if msg_type == "content_block_delta" && let Some(delta) = json.get("delta") {
 720→    if msg_type == "content_block_delta" {
 721→        if let Some(delta) = json.get("delta") {
 722→            if delta.get("type").and_then(|t| t.as_str()) == Some("text_delta") {
 723→                if let Some(text) = delta.get("text").and_then(|t| t.as_str()) {
 724→                    return StreamJsonEvent::Text {
 725→                        text: text.to_string(),
 726→                    };
 727→                }
 728→            }
 729→            if delta.get("type").and_then(|t| t.as_str()) == Some("thinking_delta") {
 730→                if let Some(text) = delta.get("thinking").and_then(|t| t.as_str()) {
 731→                    return StreamJsonEvent::Thinking {
 732→                        text: text.to_string(),
 733→                    };
 734→                }
 735→            }
 736→        }
 737→    }
 738→
 739→    // VERBOSE: Three levels of nesting for tool_use detection.
 740→    // Could be one flat let-chain condition.
 741→    if msg_type == "content_block_start" {
 742→        if let Some(cb) = json.get("content_block") {
 743→            if cb.get("type").and_then(|t| t.as_str()) == Some("tool_use") {
 744→                let tool_name = cb
 745→                    .get("name")
 746→                    .and_then(|n| n.as_str())
 747→                    .unwrap_or("unknown")
 748→                    .to_string();
 749→                let tool_id = cb
 750→                    .get("id")
 751→                    .and_then(|i| i.as_str())
 752→                    .unwrap_or("")
 753→                    .to_string();
 754→                return StreamJsonEvent::ToolStart {
 755→                    tool_name,
 756→                    tool_id,
 757→                    input_summary: String::new(),
 758→                };
 759→            }
 760→        }
 761→    }
 762→
 763→    // VERBOSE: Another nested pattern for assistant message parsing.
 764→    if json.get("role").and_then(|r| r.as_str()) == Some("assistant") {
 765→        if let Some(content) = json.get("content").and_then(|c| c.as_array()) {
 766→            for block in content {
 767→                if block.get("type").and_then(|t| t.as_str()) == Some("tool_use") {
 768→                    let tool_name = block
 769→                        .get("name")
 770→                        .and_then(|n| n.as_str())
 771→                        .unwrap_or("unknown")
 772→                        .to_string();
 773→                    let tool_id = block
 774→                        .get("id")
 775→                        .and_then(|i| i.as_str())
 776→                        .unwrap_or("")
 777→                        .to_string();
 778→                    return StreamJsonEvent::ToolStart {
 779→                        tool_name,
 780→                        tool_id,
 781→                        input_summary: String::new(),
 782→                    };
 783→                }
 784→            }
 785→        }
 786→    }
