105→   105→   105→            Self::Manual => 0,        // Manual never auto-fixes
106→   106→   106→            Self::Auto { max_attempts } => *max_attempts,
107→   107→   107→            Self::Arbiter { .. } => 2,  // Arbiter defaults to 2
