516→   516→/// does not differentiate it from Standard. No code path checks for Strict specifically.
517→   517→#[derive(Debug, Clone, Copy, PartialEq, Eq, Default, Serialize, Deserialize)]
518→   518→#[serde(rename_all = "lowercase")]
519→   519→pub enum PermissionMode {
520→   520→    /// Require approval for every iteration (sensitive phases).
521→   521→    /// DEAD: No gate logic differentiates this from Standard.
522→   522→    Strict,
523→   523→    /// Approve phase start, auto-continue iterations (default).
524→   524→    #[default]
525→   525→    Standard,
526→   526→    /// Auto-approve all iterations.
527→   527→    Autonomous,
528→   528→    /// Read-only: restrict to read-only tools.
529→   529→    Readonly,
530→   530→}
