536→   536→            PermissionMode::Standard => write!(f, "standard"),
537→   537→            PermissionMode::Autonomous => write!(f, "autonomous"),
538→   538→            PermissionMode::Readonly => write!(f, "readonly"),
539→   539→        }
540→   540→    }
541→   541→}
