547→   547→        match s.to_lowercase().as_str() {
548→   548→            "strict" => Ok(PermissionMode::Strict),
549→   549→            "standard" => Ok(PermissionMode::Standard),
550→   550→            "autonomous" => Ok(PermissionMode::Autonomous),
551→   551→            "readonly" => Ok(PermissionMode::Readonly),
552→   552→            _ => anyhow::bail!(
