560→   560→/// Returns restricted tool set for a permission mode, or None for unrestricted modes.
561→   561→///
562→   562→/// NOTE: Strict returns None (unrestricted) — identical to Standard.
563→   563→/// If Strict truly required manual approval, this function would need to return
564→   564→/// a different tool set or the gate logic would need a separate check.
565→   565→pub fn tools_for_permission_mode(mode: PermissionMode) -> Option<Vec<String>> {
566→   566→    match mode {
