        }
        _ => {
            // Unknown verdict defaults to Escalate — which is also dead
            ArbiterDecision::escalate(
                &format!("Unrecognized verdict '{}', defaulting to escalate", verdict_str),
                0.0,
                "LLM returned unrecognized verdict",
            )
        }
    }
}

